def validate_file_completeness() -> Tuple[bool, List[str], Dict[str, Any]]:
    """
    Validate that all expected output files exist from Steps 0-9.
    Returns (all_exist, missing_files, file_info).
    """
    log("[VALIDATION] Checking file completeness...")
    
    missing_files = []
    file_info = {}
    
    for file_path, metadata in EXPECTED_FILES.items():
        full_path = PROJECT_ROOT / file_path
        exists = full_path.exists()
        
        if exists:
            # Get file stats
            stat = full_path.stat()
            file_info[file_path] = {
                "exists": True,
                "size_bytes": stat.st_size,
                "modified": datetime.fromtimestamp(stat.st_mtime).isoformat(),
                "type": metadata["type"],
                "description": metadata["description"]
            }
            log(f"  [PASS] {file_path} ({stat.st_size} bytes)")
        else:
            missing_files.append(file_path)
            file_info[file_path] = {
                "exists": False,
                "size_bytes": 0,
                "type": metadata["type"],
                "description": metadata["description"]
            }
            if metadata["required"]:
                log(f"  [FAIL] {file_path} (MISSING - REQUIRED)")
            else:
                log(f"  [WARN] {file_path} (missing - optional)")
    
    # Check log files
    log("\n[VALIDATION] Checking log file completeness...")
    for log_path in EXPECTED_LOG_FILES:
        full_path = PROJECT_ROOT / log_path
        exists = full_path.exists()
        
        if exists:
            stat = full_path.stat()
            file_info[log_path] = {
                "exists": True,
                "size_bytes": stat.st_size,
                "modified": datetime.fromtimestamp(stat.st_mtime).isoformat(),
                "type": "execution_log",
                "description": "Step execution log"
            }
            log(f"  [PASS] {log_path} ({stat.st_size} bytes)")
        else:
            missing_files.append(log_path)
            file_info[log_path] = {
                "exists": False,
                "size_bytes": 0,
                "type": "execution_log",
                "description": "Step execution log"
            }
            log(f"  [WARN] {log_path} (missing log file)")
    
    all_exist = len(missing_files) == 0
    return all_exist, missing_files, file_info

def validate_data_integrity() -> Tuple[bool, List[str], Dict[str, Any]]:
    """
    Spot-check key statistical results for data integrity.
    Returns (integrity_ok, issues, integrity_report).
    """
    log("\n[VALIDATION] Checking data integrity...")
    
    issues = []
    integrity_report = {}
    
    try:
        # Check Step 1: Analysis dataset structure
        step01_path = PROJECT_ROOT / "results/ch7/7.2.1/data/step01_analysis_dataset.csv"
        if step01_path.exists():
            df1 = pd.read_csv(step01_path)
            
            # Check row count
            n_rows = len(df1)
            expected_min, expected_max = EXPECTED_FILES["results/ch7/7.2.1/data/step01_analysis_dataset.csv"]["expected_rows"]
            
            if expected_min <= n_rows <= expected_max:
                log(f"  [PASS] Analysis dataset: {n_rows} rows (within {expected_min}-{expected_max})")
                integrity_report["step01_rows"] = {"status": "PASS", "value": n_rows, "expected": f"{expected_min}-{expected_max}"}
            else:
                issue = f"Analysis dataset has {n_rows} rows, expected {expected_min}-{expected_max}"
                issues.append(issue)
                log(f"  [FAIL] {issue}")
                integrity_report["step01_rows"] = {"status": "FAIL", "value": n_rows, "expected": f"{expected_min}-{expected_max}"}
            
            # Check for missing data
            missing_count = df1.isnull().sum().sum()
            if missing_count == 0:
                log(f"  [PASS] Analysis dataset: No missing data")
                integrity_report["step01_missing"] = {"status": "PASS", "value": missing_count}
            else:
                issue = f"Analysis dataset has {missing_count} missing values"
                issues.append(issue)
                log(f"  [FAIL] {issue}")
                integrity_report["step01_missing"] = {"status": "FAIL", "value": missing_count}
                
        else:
            issues.append("Analysis dataset file missing")
            integrity_report["step01_rows"] = {"status": "FAIL", "value": "FILE_MISSING"}
            integrity_report["step01_missing"] = {"status": "FAIL", "value": "FILE_MISSING"}
        
        # Check Step 2: Correlations within valid range
        step02_path = PROJECT_ROOT / "results/ch7/7.2.1/data/step02_correlations.csv"
        if step02_path.exists():
            df2 = pd.read_csv(step02_path)
            
            if 'r' in df2.columns:
                r_min, r_max = df2['r'].min(), df2['r'].max()
                if -1.0 <= r_min <= r_max <= 1.0:
                    log(f"  [PASS] Correlations: r in [{r_min:.3f}, {r_max:.3f}] (valid range)")
                    integrity_report["step02_correlations"] = {"status": "PASS", "range": [r_min, r_max]}
                else:
                    issue = f"Correlations out of bounds: r in [{r_min:.3f}, {r_max:.3f}]"
                    issues.append(issue)
                    log(f"  [FAIL] {issue}")
                    integrity_report["step02_correlations"] = {"status": "FAIL", "range": [r_min, r_max]}
            else:
                issues.append("Correlation file missing 'r' column")
                integrity_report["step02_correlations"] = {"status": "FAIL", "value": "MISSING_COLUMN"}
                
        # Check Step 3: R² values within valid range
        step03_path = PROJECT_ROOT / "results/ch7/7.2.1/data/step03_hierarchical_models.csv"
        if step03_path.exists():
            df3 = pd.read_csv(step03_path)
            
            if 'R2' in df3.columns:
                r2_min, r2_max = df3['R2'].min(), df3['R2'].max()
                if 0.0 <= r2_min <= r2_max <= 1.0:
                    log(f"  [PASS] R-squared: R² in [{r2_min:.3f}, {r2_max:.3f}] (valid range)")
                    integrity_report["step03_r2"] = {"status": "PASS", "range": [r2_min, r2_max]}
                else:
                    issue = f"R-squared out of bounds: R² in [{r2_min:.3f}, {r2_max:.3f}]"
                    issues.append(issue)
                    log(f"  [FAIL] {issue}")
                    integrity_report["step03_r2"] = {"status": "FAIL", "range": [r2_min, r2_max]}
            else:
                issues.append("Hierarchical models file missing 'R2' column")
                integrity_report["step03_r2"] = {"status": "FAIL", "value": "MISSING_COLUMN"}
        
        # Check Step 4: Mediation proportions reasonable  
        step04_path = PROJECT_ROOT / "results/ch7/7.2.1/data/step04_mediation_analysis.csv"
        if step04_path.exists():
            df4 = pd.read_csv(step04_path)
            
            if 'proportion_mediated' in df4.columns:
                prop_min, prop_max = df4['proportion_mediated'].min(), df4['proportion_mediated'].max()
                # Allow broader range for proportion mediated (can exceed [0,1])
                if -2.0 <= prop_min <= prop_max <= 2.0:
                    log(f"  [PASS] Mediation: proportion in [{prop_min:.3f}, {prop_max:.3f}] (reasonable range)")
                    integrity_report["step04_mediation"] = {"status": "PASS", "range": [prop_min, prop_max]}
                else:
                    issue = f"Mediation proportion extreme: [{prop_min:.3f}, {prop_max:.3f}]"
                    issues.append(issue)
                    log(f"  [WARN] {issue} (may be valid but extreme)")
                    integrity_report["step04_mediation"] = {"status": "WARN", "range": [prop_min, prop_max]}
            else:
                issues.append("Mediation file missing 'proportion_mediated' column")
                integrity_report["step04_mediation"] = {"status": "FAIL", "value": "MISSING_COLUMN"}
                
    except Exception as e:
        issue = f"Data integrity check failed: {str(e)}"
        issues.append(issue)
        log(f"  [ERROR] {issue}")
        integrity_report["error"] = str(e)
    
    integrity_ok = len(issues) == 0
    return integrity_ok, issues, integrity_report

def validate_statistical_consistency() -> Tuple[bool, List[str], Dict[str, Any]]:
    """
    Cross-check statistical consistency across files.
    Returns (consistent, inconsistencies, consistency_report).
    """
    log("\n[VALIDATION] Checking statistical consistency...")
    
    inconsistencies = []
    consistency_report = {}
    
    try:
        # Check if correlation results align with regression R²
        step02_path = PROJECT_ROOT / "results/ch7/7.2.1/data/step02_correlations.csv"
        step03_path = PROJECT_ROOT / "results/ch7/7.2.1/data/step03_hierarchical_models.csv"
        
        if step02_path.exists() and step03_path.exists():
            df_corr = pd.read_csv(step02_path)
            df_reg = pd.read_csv(step03_path)
            
            # Find Age-theta_all correlation
            age_theta_corr = None
            if 'Variable1' in df_corr.columns and 'Variable2' in df_corr.columns and 'r' in df_corr.columns:
                age_theta_rows = df_corr[
                    ((df_corr['Variable1'] == 'Age') & (df_corr['Variable2'] == 'theta_all')) |
                    ((df_corr['Variable1'] == 'theta_all') & (df_corr['Variable2'] == 'Age'))
                ]
                if len(age_theta_rows) > 0:
                    age_theta_corr = age_theta_rows.iloc[0]['r']
            
            # Find Model 1 (Age only) R²
            model1_r2 = None
            if 'model' in df_reg.columns and 'R2' in df_reg.columns:
                model1_rows = df_reg[df_reg['model'].str.contains('Model_1', case=False, na=False)]
                if len(model1_rows) > 0:
                    model1_r2 = model1_rows.iloc[0]['R2']
            
            # Check consistency: R² should ≈ r²
            if age_theta_corr is not None and model1_r2 is not None:
                expected_r2 = age_theta_corr ** 2
                r2_diff = abs(model1_r2 - expected_r2)
                
                if r2_diff <= 0.01:  # Within rounding error
                    log(f"  [PASS] Age-theta correlation consistent: r={age_theta_corr:.3f}, R²={model1_r2:.3f} (expected {expected_r2:.3f})")
                    consistency_report["age_theta_consistency"] = {
                        "status": "PASS", 
                        "correlation": age_theta_corr,
                        "r2_actual": model1_r2,
                        "r2_expected": expected_r2,
                        "difference": r2_diff
                    }
                else:
                    issue = f"Age-theta inconsistency: r={age_theta_corr:.3f} implies R²={expected_r2:.3f}, but Model 1 R²={model1_r2:.3f} (diff={r2_diff:.3f})"
                    inconsistencies.append(issue)
                    log(f"  [FAIL] {issue}")
                    consistency_report["age_theta_consistency"] = {
                        "status": "FAIL",
                        "correlation": age_theta_corr,
                        "r2_actual": model1_r2, 
                        "r2_expected": expected_r2,
                        "difference": r2_diff
                    }
            else:
                log("  [WARN] Cannot check Age-theta consistency (missing data)")
                consistency_report["age_theta_consistency"] = {"status": "WARN", "reason": "missing_data"}
        
        # Check that cross-validation R² is reasonable compared to fitted R²
        step05_path = PROJECT_ROOT / "results/ch7/7.2.1/data/step05_cross_validation.csv"
        if step05_path.exists() and step03_path.exists():
            df_cv = pd.read_csv(step05_path)
            df_reg = pd.read_csv(step03_path)
            
            # Get Model 2 fitted R² and cross-validated R²
            if 'cv_R2_mean' in df_cv.columns and 'model' in df_cv.columns:
                model2_cv_rows = df_cv[df_cv['model'].str.contains('Model_2', case=False, na=False)]
                if len(model2_cv_rows) > 0:
                    cv_r2 = model2_cv_rows.iloc[0]['cv_R2_mean']
                    
                    # Get fitted R² for Model 2
                    model2_fitted_rows = df_reg[df_reg['model'].str.contains('Model_2', case=False, na=False)]
                    if len(model2_fitted_rows) > 0:
                        fitted_r2 = model2_fitted_rows.iloc[0]['R2']
                        
                        # Cross-validated R² should be lower but not drastically
                        cv_penalty = fitted_r2 - cv_r2
                        if 0 <= cv_penalty <= 0.3:  # Reasonable cross-validation penalty
                            log(f"  [PASS] Cross-validation reasonable: fitted R²={fitted_r2:.3f}, CV R²={cv_r2:.3f} (penalty={cv_penalty:.3f})")
                            consistency_report["cv_consistency"] = {
                                "status": "PASS",
                                "fitted_r2": fitted_r2,
                                "cv_r2": cv_r2,
                                "penalty": cv_penalty
                            }
                        else:
                            issue = f"Cross-validation penalty unreasonable: fitted R²={fitted_r2:.3f}, CV R²={cv_r2:.3f} (penalty={cv_penalty:.3f})"
                            inconsistencies.append(issue)
                            log(f"  [WARN] {issue}")
                            consistency_report["cv_consistency"] = {
                                "status": "WARN",
                                "fitted_r2": fitted_r2,
                                "cv_r2": cv_r2,
                                "penalty": cv_penalty
                            }
                    else:
                        log("  [WARN] Cannot find Model 2 fitted R² for cross-validation check")
                        consistency_report["cv_consistency"] = {"status": "WARN", "reason": "missing_model2_fitted"}
                else:
                    log("  [WARN] Cannot find Model 2 cross-validation results")
                    consistency_report["cv_consistency"] = {"status": "WARN", "reason": "missing_model2_cv"}
            else:
                log("  [WARN] Cross-validation file missing required columns")
                consistency_report["cv_consistency"] = {"status": "WARN", "reason": "missing_columns"}
                
    except Exception as e:
        issue = f"Statistical consistency check failed: {str(e)}"
        inconsistencies.append(issue)
        log(f"  [ERROR] {issue}")
        consistency_report["error"] = str(e)
    
    consistent = len(inconsistencies) == 0
    return consistent, inconsistencies, consistency_report

def verify_reproducibility_markers() -> Tuple[bool, List[str], Dict[str, Any]]:
    """
    Verify that random seeds and bootstrap iterations are documented.
    Returns (reproducible, missing_markers, reproducibility_report).
    """
    log("\n[VALIDATION] Checking reproducibility markers...")
    
    missing_markers = []
    reproducibility_report = {}
    
    # Check for random seed documentation in analysis files
    bootstrap_files = [
        ("step02_correlations", "Bootstrap correlation CIs"),
        ("step04_mediation_analysis", "Bootstrap mediation analysis"),
        ("step05_cross_validation", "Cross-validation")
    ]
    
    for step_name, description in bootstrap_files:
        # Check if corresponding data files have reasonable bootstrap results
        file_path = PROJECT_ROOT / f"results/ch7/7.2.1/data/{step_name}.csv"
        if file_path.exists():
            try:
                df = pd.read_csv(file_path)
                
                # Check for confidence intervals (indicator of bootstrap)
                has_ci = any(col for col in df.columns if 'ci_' in col.lower() or 'ci' in col.lower())
                
                if has_ci:
                    log(f"  [PASS] {description}: Confidence intervals present (bootstrap likely used)")
                    reproducibility_report[step_name] = {"status": "PASS", "evidence": "confidence_intervals_present"}
                else:
                    issue = f"{description}: No confidence intervals found"
                    missing_markers.append(issue)
                    log(f"  [WARN] {issue}")
                    reproducibility_report[step_name] = {"status": "WARN", "evidence": "no_confidence_intervals"}
                    
            except Exception as e:
                issue = f"Error checking {description}: {str(e)}"
                missing_markers.append(issue)
                log(f"  [ERROR] {issue}")
                reproducibility_report[step_name] = {"status": "ERROR", "error": str(e)}
        else:
            issue = f"{description}: File missing"
            missing_markers.append(issue)
            log(f"  [FAIL] {issue}")
            reproducibility_report[step_name] = {"status": "FAIL", "evidence": "file_missing"}
    
    # Check log files for random seed mentions
    log_files_checked = 0
    seed_mentions_found = 0
    
    for log_path in EXPECTED_LOG_FILES:
        full_path = PROJECT_ROOT / log_path
        if full_path.exists():
            try:
                with open(full_path, 'r', encoding='utf-8') as f:
                    content = f.read()
                    
                # Look for seed-related keywords
                seed_keywords = ['random_state', 'seed', 'bootstrap', 'random']
                has_seed_mention = any(keyword in content.lower() for keyword in seed_keywords)
                
                if has_seed_mention:
                    seed_mentions_found += 1
                    
                log_files_checked += 1
                
            except Exception as e:
                log(f"  [WARN] Error reading {log_path}: {str(e)}")
    
    if log_files_checked > 0:
        seed_ratio = seed_mentions_found / log_files_checked
        if seed_ratio >= 0.5:  # At least half of logs mention seeds/randomness
            log(f"  [PASS] Reproducibility markers: {seed_mentions_found}/{log_files_checked} log files mention randomness")
            reproducibility_report["log_seed_mentions"] = {"status": "PASS", "ratio": seed_ratio, "count": seed_mentions_found, "total": log_files_checked}
        else:
            issue = f"Few seed mentions: {seed_mentions_found}/{log_files_checked} log files"
            missing_markers.append(issue)
            log(f"  [WARN] {issue}")
            reproducibility_report["log_seed_mentions"] = {"status": "WARN", "ratio": seed_ratio, "count": seed_mentions_found, "total": log_files_checked}
    else:
        issue = "No log files found to check for seed documentation"
        missing_markers.append(issue)
        log(f"  [FAIL] {issue}")
        reproducibility_report["log_seed_mentions"] = {"status": "FAIL", "reason": "no_log_files"}
    
    reproducible = len(missing_markers) == 0
    return reproducible, missing_markers, reproducibility_report

def generate_execution_report(file_info: Dict[str, Any]) -> Dict[str, Any]:
    """
    Generate execution report showing success/failure for each step.
    Returns execution report dictionary.
    """
    log("\n[VALIDATION] Generating execution report...")
    
    execution_report = {}
    
    # Map files to steps
    step_files = {}
    for file_path, info in file_info.items():
        if "step" in file_path:
            # Extract step number from file path
            try:
                step_part = Path(file_path).name
                if step_part.startswith("step"):
                    step_num = step_part[4:6]  # Extract "00", "01", etc.
                    if step_num not in step_files:
                        step_files[step_num] = []
                    step_files[step_num].append((file_path, info))
            except:
                pass
    
    # Evaluate each step
    for step_num in sorted(step_files.keys()):
        files = step_files[step_num]
        
        # Count files that exist
        total_files = len(files)
        existing_files = sum(1 for _, info in files if info["exists"])
        
        # Determine step status
        if existing_files == total_files:
            status = "SUCCESS"
        elif existing_files > 0:
            status = "PARTIAL"
        else:
            status = "FAILED"
        
        execution_report[f"step{step_num}"] = {
            "status": status,
            "files_expected": total_files,
            "files_present": existing_files,
            "files": [{"path": path, "exists": info["exists"], "size": info["size_bytes"]} for path, info in files]
        }
        
        log(f"  Step {step_num}: {status} ({existing_files}/{total_files} files)")
    
    return execution_report

def create_archive_manifest(file_info: Dict[str, Any], execution_report: Dict[str, Any]) -> str:
    """
    Create comprehensive archive manifest with file descriptions and metadata.
    Returns manifest content as string.
    """
    log("\n[VALIDATION] Creating archive manifest...")
    
    manifest_lines = []
    manifest_lines.append("="*80)
    manifest_lines.append("RQ 7.2.1 ARCHIVE MANIFEST")
    manifest_lines.append("Age Moderation of Test-VR Relationship")
    manifest_lines.append("="*80)
    manifest_lines.append(f"Generated: {datetime.now().isoformat()}")
    manifest_lines.append(f"Total files: {len(file_info)}")
    manifest_lines.append("")
    
    # Analysis summary
    total_files = len(file_info)
    existing_files = sum(1 for info in file_info.values() if info["exists"])
    total_size = sum(info["size_bytes"] for info in file_info.values() if info["exists"])
    
    manifest_lines.append("ARCHIVE SUMMARY")
    manifest_lines.append("-" * 40)
    manifest_lines.append(f"Files present: {existing_files}/{total_files}")
    manifest_lines.append(f"Total size: {total_size:,} bytes ({total_size/1024/1024:.2f} MB)")
    manifest_lines.append("")
    
    # Execution summary
    manifest_lines.append("EXECUTION SUMMARY")
    manifest_lines.append("-" * 40)
    for step, info in execution_report.items():
        manifest_lines.append(f"{step.upper()}: {info['status']} ({info['files_present']}/{info['files_expected']} files)")
    manifest_lines.append("")
    
    # File inventory by type
    file_types = {}
    for path, info in file_info.items():
        file_type = info.get("type", "unknown")
        if file_type not in file_types:
            file_types[file_type] = []
        file_types[file_type].append((path, info))
    
    manifest_lines.append("FILE INVENTORY BY TYPE")
    manifest_lines.append("-" * 40)
    
    for file_type in sorted(file_types.keys()):
        files = file_types[file_type]
        manifest_lines.append(f"\n{file_type.upper()} ({len(files)} files):")
        
        for path, info in sorted(files):
            status = "PRESENT" if info["exists"] else "MISSING"
            size_str = f"{info['size_bytes']:,} bytes" if info["exists"] else "N/A"
            manifest_lines.append(f"  [{status}] {path}")
            manifest_lines.append(f"           {info['description']}")
            manifest_lines.append(f"           Size: {size_str}")
            if info["exists"] and "modified" in info:
                manifest_lines.append(f"           Modified: {info['modified']}")
            manifest_lines.append("")
    
    # Reproducibility information
    manifest_lines.append("REPRODUCIBILITY MARKERS")
    manifest_lines.append("-" * 40)
    manifest_lines.append("Random seeds: Documented in analysis specifications (random_state=42)")
    manifest_lines.append("Bootstrap iterations: 1000 iterations used for confidence intervals")
    manifest_lines.append("Cross-validation: 5-fold cross-validation with stratification")
    manifest_lines.append("Analysis pipeline: Fully specified in 4_analysis.yaml")
    manifest_lines.append("")
    
    # Data dependencies
    manifest_lines.append("DATA DEPENDENCIES")
    manifest_lines.append("-" * 40)
    manifest_lines.append("External dependencies:")
    manifest_lines.append("  - results/ch5/5.1.1/data/step03_theta_scores.csv (IRT ability estimates)")
    manifest_lines.append("  - data/dfnonvr.csv (cognitive test scores and demographics)")
    manifest_lines.append("")
    manifest_lines.append("Analysis outputs feed into:")
    manifest_lines.append("  - rq_plots agent for visualization generation")
    manifest_lines.append("  - rq_results agent for thesis integration")
    manifest_lines.append("")
    
    # Technical specifications
    manifest_lines.append("TECHNICAL SPECIFICATIONS")
    manifest_lines.append("-" * 40)
    manifest_lines.append("Analysis type: Hierarchical Multiple Regression with Bootstrap Mediation")
    manifest_lines.append("Sample size: ~100 participants")
    manifest_lines.append("Statistical corrections: Bonferroni + FDR (Decision D068 compliance)")
    manifest_lines.append("Cross-validation: 5-fold stratified")
    manifest_lines.append("Bootstrap iterations: 1000")
    manifest_lines.append("Confidence level: 95%")
    manifest_lines.append("Random seed: 42 (reproducibility)")
    manifest_lines.append("")
    
    manifest_lines.append("="*80)
    manifest_lines.append("END OF MANIFEST")
    manifest_lines.append("="*80)
    
    return "\n".join(manifest_lines)

